def dedup_report(rows, key='id'):
    seen, unique, conflicts = {}, [], []
    for r in rows:
        rid = r[key]
        if rid not in seen:
            seen[rid] = r
            unique.append(r)
        elif seen[rid] != r:
            conflicts.append({'id': rid, 'a': seen[rid], 'b': r})
    return {'unique': unique, 'conflicts': conflicts}
